class _LegendDatum {
  const _LegendDatum({
    required this.label,
    required this.value,
    required this.color,
    required this.percentage,
  });

  final String label;
  final String value;
  final Color color;
  final double percentage;
}

class _DonutChart extends StatelessWidget {
  const _DonutChart({required this.data});

  final List<_LegendDatum> data;

  @override
  Widget build(BuildContext context) {
    return CustomPaint(
      painter: _DonutPainter(data),
      child: const Center(
        child: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            Text(
              '1,309',
              style: TextStyle(
                color: Color(0xFF172554),
                fontWeight: FontWeight.w800,
                fontSize: 22,
              ),
            ),
            Text(
              'Total Qty',
              style: TextStyle(
                color: Color(0xFF475569),
                fontWeight: FontWeight.w600,
              ),
            ),
          ],
        ),
      ),
    );
  }
}

class _DonutPainter extends CustomPainter {
  _DonutPainter(this.data);

  final List<_LegendDatum> data;

  @override
  void paint(Canvas canvas, Size size) {
    const strokeWidth = 26.0;
    final rect = Offset.zero & size;
    final center = rect.center;
    final radius = (math.min(size.width, size.height) - strokeWidth) / 2;
    final arcRect = Rect.fromCircle(center: center, radius: radius);
    final background = Paint()
      ..color = const Color(0xFFEAF0F7)
      ..style = PaintingStyle.stroke
      ..strokeWidth = strokeWidth
      ..strokeCap = StrokeCap.round;

    canvas.drawArc(arcRect, 0, math.pi * 2, false, background);

    final paint = Paint()
      ..style = PaintingStyle.stroke
      ..strokeWidth = strokeWidth
      ..strokeCap = StrokeCap.butt;

    double startAngle = -math.pi / 2;
    for (final item in data) {
      final sweep = math.pi * 2 * item.percentage;
      paint.color = item.color;
      canvas.drawArc(arcRect, startAngle, sweep, false, paint);
      startAngle += sweep;
    }
  }

  @override
  bool shouldRepaint(covariant _DonutPainter oldDelegate) {
    return oldDelegate.data != data;
  }
}

